class Solution:
    def maximumTotalCost(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 1:
            return nums[0]

        # dp[i] represents the maximum total cost up to index i
        dp = [0] * n
        dp[0] = nums[0]

        for i in range(1, n):
            # Case 1: extend the previous subarray
            dp[i] = dp[i - 1] + nums[i] * (-1) ** (i - 0)

            # Case 2: start a new subarray at i
            if i > 0:
                dp[i] = max(dp[i], dp[i - 1] + nums[i])

        return dp[-1]
